package com.teamspace.teamspace.task.controller;
import java.util.List; import org.springframework.security.core.Authentication; import org.springframework.web.bind.annotation.*; import com.teamspace.teamspace.common.ApiResponse; import com.teamspace.teamspace.task.dto.TaskWatcherResponse; import com.teamspace.teamspace.task.service.TaskWatcherService; import lombok.RequiredArgsConstructor;
@RestController @RequestMapping("/api/tasks/{taskId}/watchers") @RequiredArgsConstructor public class TaskWatcherController{private final TaskWatcherService service;@GetMapping public ApiResponse<List<TaskWatcherResponse>> list(@PathVariable Long taskId,Authentication a){return ApiResponse.success("Lay nguoi theo doi thanh cong",service.list(taskId,a));}@PostMapping("/me")public ApiResponse<TaskWatcherResponse> follow(@PathVariable Long taskId,Authentication a){return ApiResponse.success("Theo doi task thanh cong",service.follow(taskId,a));}@DeleteMapping("/me")public ApiResponse<Void> unfollow(@PathVariable Long taskId,Authentication a){service.unfollow(taskId,a);return ApiResponse.success("Bo theo doi task thanh cong",null);}}
